"user strict";$(()=>{const a=document.getElementById("assign-carrier-modal"),b=document.getElementById("assign-carrier-modal-refresh-btn");a.addEventListener("show.bs.modal",()=>{getAssignOrderView()}),b.addEventListener("click",()=>{getAssignOrderView()})});function getAssignOrderView(){$.ajax({type:"GET",url:MAIN_URL+"/delivery/carrier/assign/view",data:{order_id:orderId},dataType:"html",cache:!1,beforeSend:()=>{$("#assign-carrier-modal-body").html(`<div class="d-flex justify-content-center"> <div class="placeholder wave p-0 mx-2 my-2 order-sec-head"> <div class="square"></div></div></div><div class="d-flex justify-content-center"> <div class="placeholder wave p-0 mx-2 my-2 h-15p"> <div class="square"></div></div></div><div class="d-flex justify-content-center"> <div class="placeholder wave p-0 mx-2 my-2 h-15p"> <div class="square"></div></div></div><div class="d-flex justify-content-center"> <div class="placeholder wave p-0 mx-2 my-4 h-40"> <div class="square"></div></div></div><div class="d-flex justify-content-center"> <div class="placeholder wave p-0 mx-2 my-2 h-20"> <div class="square"></div></div></div><div class="d-flex justify-content-center"> <div class="placeholder wave p-0 mx-2 my-2 h-20"> <div class="square"></div></div></div>`)},success:a=>{if(a){$("#assign-carrier-modal-body").html(a);const b=document.getElementById("search_carrier");b.addEventListener("input",function(a){searchAndPopulateCarrierTable(a.target.value)}),$(".assign-carrier-btn").on("click",a=>{assignToOrder($(a.target))})}},fail:()=>{$("#assign-carrier-modal-body").html(`<div class="d-flex justify-content-center"><span>Something went wrong!</span></div>`)}})}function searchAndPopulateCarrierTable(a){$.ajax({type:"GET",url:ROOT_URL+"/delivery/ajax/carrier/search/available",delay:250,beforeSend:()=>{$("#carrier_search_spinner").removeClass("d-none")},dataType:"json",data:{q:a},success:a=>{let b=a.data;$("#carrier_table tbody").empty(),0<b.length?b.forEach(a=>{$("#carrier_table > tbody").append(`<tr><td class="text-center">${a.unique_id}</td><td class="text-center">${a.name}</td><td class="text-center">${a.assigned_order_count}</td><td class="text-center"><button type="button" class="btn btn-primary btn-sm assign-carrier-btn" data-id="${a.id}"><span class="fa fa-plus"></span><span class="fa fa-solid fa-cog fa-spin d-none"></span><span class="ps-1">Assign</span></button></td></tr>`),$(".assign-carrier-btn").on("click",a=>{assignToOrder($(a.target))})}):$("#carrier_table > tbody").append(`<tr><td colspan="4" class="text-center">No record found!</td></tr>`),$("#carrier_search_spinner").addClass("d-none")}})}function assignToOrder(a){let b=a;a.is("button")||(b=a.parent());let c=b.data("id");$.ajax({type:"POST",url:ROOT_URL+"/delivery/ajax/carrier/assign",data:{_token:token,delivery_man_id:c,order_id:orderId},dataType:"json",beforeSend:function(){b.find("span.fa-cog").removeClass("d-none"),b.find("span.fa-plus").addClass("d-none")},success:a=>{b.find("span.fa-plus").removeClass("d-none"),b.find("span.fa-cog").addClass("d-none"),$("#carrier-modal-alert").empty(),a.is_assigned?$("#carrier-modal-alert").append(`<div class="alert alert-success alert-dismissible fade show" role="alert">${a.message}</div>`).hide().slideDown(500):$("#carrier-modal-alert").append(`<div class="alert alert-danger alert-dismissible fade show" role="alert">${a.message}</div>`).hide().slideDown(500),$(".alert-dismissible").fadeTo(2e3,500).slideUp(2e3,function(){$(".alert-dismissible").alert("close")})},fail:()=>{$("#carrier-modal-alert").empty(),$("#carrier-modal-alert").append(`<div class="alert alert-danger alert-dismissible fade show" role="alert">Something went wrong!</div>`).hide().slideDown(500),$(".alert-dismissible").fadeTo(2e3,500).slideUp(2e3,function(){$(".alert-dismissible").alert("close")})}})}
